vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec3 base = GetBlur3(vUv) + GetBlur2(vUv) + GetBlur1(vUv) + texture(sampler_main, vUv)*0.94 - 0.39 ;
a =base.x/8;b = base.y/8; c = base.x/3;
c = c + b + a*b;
a = a + c + a*c;
base = .2+a;
ret = base*(.8-base)*(0.7-base)*2*vec3(1,1,2.4) + pow(base,2)*vec3(.4,1,2);
//ret.xy = ret.yx;
ret = mix(ret,vec3(1.6,2,2.1),GetPixel(vUv).y);


  fragColor = ret;
}
